def route_model\(avg_flow_size\):
    if avg_flow_size < 200 * 1024:
        return 'server'
    elif avg_flow_size < 1 * 1024 * 1024:
        return 'cache'
    elif avg_flow_size < 3 * 1024 * 1024:
        return 'search'
    else:
        return 'mine'

for name, val in config.items\(\):
    routed = route_model\(val\)
    status = 'OK' if routed == name else 'MISMATCH'
    print\(f'{name:8s} avg_flow_size={val/1024:.1f} KB -> routes to {routed:8s} [{status}]'\)

print\(\)
print\('--- Boundary checks ---'\)
boundaries = [200*1024, 1*1024*1024, 3*1024*1024]
for b in boundaries:
    print\(f'  route_model\({b}\) = {route_model\(b\)}  \(exactly at boundary\)'\)
    print\(f'  route_model\({b-1}\) = {route_model\(b-1\)}  \(just below\)'\)
